    useEffect(() => {
        if (!id) return;
        // Use String() for ID comparison to handle potential number/string mismatches from URL/Data
        const foundClient = clients.find(c => String(c.id) === String(id));
        setClient(foundClient);
        setFormData(foundClient || null);
    }, [id, clients]);

    const showToast = (message: string, type: 'success' | 'error') => {
        setToast({ message, type });
    };

    // Template Logic
    useEffect(() => {
        if (mode === 'message' && templates.length > 0 && !selectedTemplateName && preview === '') {
            setSelectedTemplateName(templates[0]?.['Название шаблона'] || '');
        }
    }, [templates, selectedTemplateName, mode, preview]);

    useEffect(() => {
        if (selectedTemplateName && formData) {
            const selectedTemplate = templates.find(t => t['Название шаблона'] === selectedTemplateName);
            if (selectedTemplate) {
                let content = selectedTemplate['Содержимое (HTML)'];
                Object.keys(formData).forEach(key => {
                    let value = formData[key as keyof Client];
                    if ((key === 'Начало' || key === 'Окончание' || key === 'Напомнить') && typeof value === 'string') {
                        if (value.includes('T')) value = value.split('T')[0];
                    }
                    if ((key === 'Общая сумма' || key === 'Долг' || key === 'Цена за месяц') && typeof value === 'number') {
                         value = new Intl.NumberFormat('ru-RU', { style: 'currency', currency: 'RUB', minimumFractionDigits: 0 }).format(value);
                    }
                    content = content.replace(new RegExp(`{{${key}}}`, 'g'), String(value || ''));
                });
                setPreview(content);
            }
        }
    }, [selectedTemplateName, templates, formData]);

    const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
        const { name, value, type } = e.target;
        const isNumber = type === 'number';
        setFormData(prev => prev ? ({ ...prev, [name]: isNumber ? parseFloat(value) || 0 : value }) : null);
    };

    const handleSave = async () => {
        if (!formData || !formData.id) return;
        setIsSubmitting(true);
        try {
            await api.updateClient(formData as Client);
            showToast('Клиент успешно обновлен', 'success');
            await refreshData();
            setMode('view');
        } catch (e: any) {
            showToast(e.message, 'error');
        } finally {
            setIsSubmitting(false);
        }
    };

    const handleDelete = async () => {
        if (!client) return;
        if (window.confirm(`Вы уверены, что хотите удалить клиента "${client['Имя клиента']}"?`)) {
            setIsSubmitting(true);
            try {
                await api.deleteClient(client.id);
                showToast('Клиент удален', 'success');
                await refreshData();
                navigate('/clients', { replace: true });
            } catch (e: any) {
                showToast(e.message, 'error');
            } finally {
                setIsSubmitting(false);
            }
        }
    };

    const handleSendMessage = async () => {
        if (preview && client) {
            setIsSubmitting(true);
            try {
                const result = await api.sendMessage(client['Chat ID'] as string, preview);
                showToast(result.message, result.success ? 'success' : 'error');
                if (result.success) {
                    await refreshData();
                    setMode('view');
                }
            } catch(e: any) {
                showToast(e.message, 'error');
            } finally {
                setIsSubmitting(false);
            }
        }
    };

    const handleGenerateReceipt = () => {
        if (!client) return;
        const groups = getTireGroups(client);
        const formatCurrency = (val: number | undefined) => new Intl.NumberFormat('ru-RU', { style: 'currency', currency: 'RUB', minimumFractionDigits: 0 }).format(val || 0);

        let tiresText = '';
        if (groups.length > 0) {
            tiresText = groups.map((g, i) => `<b>📦 Комплект ${i + 1}:</b>\n${g.count}шт • ${g.brand} ${g.model}\nРазмер: <b>${g.width}/${g.profile} R${g.diameter}</b>\nСезон: ${g.season} | Диски: ${g.hasRims}${g.dot ? `\nDOT: <b>${g.dot}</b>` : ''}`).join('\n\n');
        } else {
            tiresText = (client['Заказ - QR'] || '').split('||JSON:')[0];
        }

        const receiptHtml = `
<b>📃 ДЕТАЛИ ЗАКАЗА (ДОГОВОР)</b>

👤 <b>Клиент:</b> ${client['Имя клиента']}
🚗 <b>Авто:</b> ${client['Номер Авто']}
📞 <b>Телефон:</b> ${client['Телефон']}

🔢 <b>Договор №:</b> <code>${client['Договор']}</code>
📅 <b>Срок хранения:</b> ${client['Срок']} мес.
(с ${formatDateForDisplay(client['Начало'])} по ${formatDateForDisplay(client['Окончание'])})

- - - - - - - - - - - - - -
${tiresText}
- - - - - - - - - - - - - -

💰 <b>Сумма заказа:</b> ${formatCurrency(client['Общая сумма'])}
(Тариф: ${formatCurrency(client['Цена за месяц'])}/мес)
${Number(client['Долг']) > 0 ? `❗️ <b>К оплате (Долг):</b> ${formatCurrency(client['Долг'])}` : ''}

📍 <b>Склад:</b> ${client['Склад хранения']}

<i>Приём и хранение осуществляется на условиях публичной оферты otelshin.ru/dogovor</i>
`.trim().replace(/\n/g, '<br/>');

        setPreview(receiptHtml);
        setSelectedTemplateName(''); 
        setMode('message');
    };

    // --- Loading & Not Found States ---

    if (clients.length === 0) {
        return (
            <div className="flex flex-col items-center justify-center h-full p-8 text-center bg-gray-100 dark:bg-gray-950">
                <div className="w-10 h-10 border-4 border-primary-200 border-t-primary-600 rounded-full animate-spin mb-4"></div>
                <p className="text-gray-500 dark:text-gray-400">Загрузка базы данных...</p>
            </div>
        );
    }

    if (!client || !formData) {
        return (
            <div className="flex flex-col items-center justify-center h-full p-8 text-center bg-gray-100 dark:bg-gray-950">
                <div className="bg-white dark:bg-gray-800 p-6 rounded-2xl shadow-sm border border-gray-200 dark:border-gray-700 max-w-sm w-full">
                    <div className="mx-auto w-12 h-12 bg-red-100 dark:bg-red-900/30 rounded-full flex items-center justify-center mb-4">
                        <svg className="w-6 h-6 text-red-600 dark:text-red-400" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>
                    </div>
                    <h3 className="text-lg font-bold text-gray-900 dark:text-white mb-2">Клиент не найден</h3>
                    <p className="text-sm text-gray-500 dark:text-gray-400 mb-6">
                        Возможно, клиент был удален или ID в ссылке указан неверно.
                    </p>
                    <Button onClick={() => navigate('/clients')} className="w-full justify-center">
                        Вернуться к списку
                    </Button>
                </div>
            </div>
        );
    }

    const descClean = (formData['Заказ - QR'] || '').split('||JSON:')[0];

    return (
        <div className="flex flex-col h-full bg-gray-100 dark:bg-gray-950">
            {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}

            {/* Sticky Header */}
            <div className="sticky top-0 z-40 bg-white/90 dark:bg-gray-900/90 backdrop-blur-md border-b border-gray-200 dark:border-gray-800 px-4 py-3 flex items-center justify-between shadow-sm">
                <div className="flex items-center gap-3 overflow-hidden">
                    <button onClick={() => navigate('/clients')} className="p-2 -ml-2 rounded-full hover:bg-gray-100 dark:hover:bg-gray-800 text-gray-600 dark:text-gray-300">
                        <ArrowLeftIcon />
                    </button>
                    <div className="flex flex-col min-w-0">
                        <h1 className="text-lg font-bold leading-tight text-gray-900 dark:text-white truncate">
                            {formData['Имя клиента']}
                        </h1>
                        <div className="flex items-center gap-2 text-xs text-gray-500 dark:text-gray-400">
                            <span className="truncate">{formData['Номер Авто']}</span>
                            {formData['Склад хранения'] && <span>• {formData['Склад хранения']}</span>}
                        </div>
                    </div>
                </div>
                <div className="flex-shrink-0">
                     <span className={`px-3 py-1 rounded-full text-xs font-bold uppercase tracking-wide ${
                         formData['Статус сделки'] === 'На складе' ? 'bg-green-100 text-green-800' : 
                         formData['Статус сделки'] === 'Завершено' ? 'bg-gray-100 text-gray-800' : 'bg-yellow-100 text-yellow-800'
                     }`}>
                         {formData['Статус сделки']}
                     </span>
                </div>
            </div>

            {/* Scrollable Content */}
            <div className="flex-1 overflow-y-auto p-4 sm:p-6 pb-24 sm:pb-6">

                {/* Mode: Edit */}
                {mode === 'edit' && (
                    <div className="max-w-2xl mx-auto space-y-4 animate-in fade-in slide-in-from-bottom-4 duration-300">
                        <div className="bg-white dark:bg-gray-800 p-4 rounded-xl shadow-sm border border-gray-200 dark:border-gray-700">
                            <h3 className="text-lg font-semibold mb-4 dark:text-white">Редактирование</h3>
                            <form onSubmit={(e) => { e.preventDefault(); handleSave(); }} className="space-y-4">
                                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                                    {headers.filter(h => h !== 'id' && h !== 'photoUrls' && h !== 'metadata').map(header => (
                                        <Input
                                            key={header}
                                            label={header}
                                            name={header}
                                            value={formData[header as keyof Client] || ''}
                                            type={getFieldType(header)}
                                            onChange={handleChange}
                                            required={header === 'Имя клиента'}
                                        />
                                    ))}
                                </div>
                            </form>
                        </div>
                    </div>
                )}

                {/* Mode: Message */}
                {mode === 'message' && (
                    <div className="max-w-2xl mx-auto space-y-4 animate-in fade-in slide-in-from-bottom-4 duration-300">
                        <div className="bg-white dark:bg-gray-800 p-4 rounded-xl shadow-sm border border-gray-200 dark:border-gray-700">
                            <h3 className="text-lg font-semibold mb-4 dark:text-white">Отправка сообщения</h3>
                            <div className="space-y-4">
                                <div>
                                    <label htmlFor="template" className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1.5">Шаблон</label>
                                    <select 
                                        id="template" 
                                        value={selectedTemplateName} 
                                        onChange={e => setSelectedTemplateName(e.target.value)} 
                                        className="block w-full rounded-md border-gray-300 shadow-sm focus:border-primary-500 focus:ring-primary-500 py-2.5 px-3 dark:bg-gray-800 dark:border-gray-600 dark:text-white transition duration-150"
                                    >
                                        <option value="">-- Индивидуальное сообщение / Чек --</option>
                                        {templates.map(t => <option key={t['Название шаблона']} value={t['Название шаблона']}>{t['Название шаблона']}</option>)}
                                    </select>
                                </div>
                                <div>
                                    <h4 className="text-md font-medium text-gray-800 dark:text-gray-200 mb-2">Сообщение (HTML)</h4>
                                    <div 
                                        className="p-3 border rounded-md bg-gray-50 dark:bg-gray-700/50 dark:border-gray-600 min-h-[150px] max-h-[40vh] overflow-y-auto font-mono text-sm whitespace-pre-wrap outline-none focus:ring-2 focus:ring-primary-500" 
                                        contentEditable
                                        onInput={(e) => setPreview(e.currentTarget.innerText)} 
                                        dangerouslySetInnerHTML={{ __html: preview }}
                                    />
                                </div>
                            </div>
                        </div>
                    </div>
                )}

                {/* Mode: View (Tabs) */}
                {mode === 'view' && (
                    <div className="max-w-4xl mx-auto space-y-6">
                        {/* Tab Nav */}
                        <div className="bg-white dark:bg-gray-800 rounded-xl p-1 shadow-sm border border-gray-200 dark:border-gray-700 flex">
                            <TabButton active={activeTab === 'details'} onClick={() => setActiveTab('details')}>Детали</TabButton>
                            <TabButton active={activeTab === 'history'} onClick={() => setActiveTab('history')}>История</TabButton>
                            <TabButton active={activeTab === 'photos'} onClick={() => setActiveTab('photos')}>Фото</TabButton>
                        </div>

                        {activeTab === 'details' && (
                            <div className="space-y-4 animate-in fade-in duration-300">
                                {/* Key Metrics Grid */}
                                <div className="grid grid-cols-2 gap-3">
                                     <div className={`p-4 rounded-xl border ${Number(formData['Долг'] || 0) > 0 ? 'bg-red-50 border-red-100 dark:bg-red-900/10 dark:border-red-800' : 'bg-green-50 border-green-100 dark:bg-green-900/10 dark:border-green-800'}`}>
                                        <p className={`text-xs font-bold uppercase tracking-wider ${Number(formData['Долг'] || 0) > 0 ? 'text-red-500' : 'text-green-500'}`}>Долг</p>
                                        <p className={`text-xl sm:text-2xl font-black mt-1 ${Number(formData['Долг'] || 0) > 0 ? 'text-red-700 dark:text-red-300' : 'text-green-700 dark:text-green-300'}`}>
                                            {new Intl.NumberFormat('ru-RU', { style: 'currency', currency: 'RUB', maximumFractionDigits: 0 }).format(Number(formData['Долг'] || 0))}
                                        </p>
                                    </div>
                                    <div className="p-4 rounded-xl bg-blue-50 border border-blue-100 dark:bg-blue-900/10 dark:border-blue-800">
                                        <p className="text-xs font-bold uppercase tracking-wider text-blue-500">Окончание</p>
                                        <p className="text-xl sm:text-2xl font-black mt-1 text-blue-700 dark:text-blue-300">{formatDateForDisplay(formData['Окончание'])}</p>
                                    </div>
                                </div>

                                {/* Contract Info */}
                                <div className="p-4 rounded-xl bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 shadow-sm flex justify-between items-center">
                                    <div>
                                        <p className="text-xs text-gray-500 uppercase font-bold">Договор №</p>
                                        <p className="text-lg font-mono font-bold text-gray-900 dark:text-white">{formData['Договор']}</p>
                                    </div>
                                    <div className="text-right">
                                        <p className="text-xs text-gray-500 uppercase font-bold">Ячейка</p>
                                        <p className="text-lg font-bold text-gray-900 dark:text-white">{formData['Ячейка'] || '—'}</p>
                                    </div>
                                </div>

                                <SectionBlock title="Шины и Хранение" icon={<TireIcon/>}>
                                     <DetailItem label="Бренд" value={formData['Бренд_Модель']} className="col-span-1 sm:col-span-2" />
                                     <DetailItem label="Размер шин" value={formData['Размер шин']} className="col-span-1 sm:col-span-2" />
                                     <TireGroupsView client={client} />
                                     <DetailItem label="Сезон" value={formData['Сезон']} />
                                     <DetailItem label="Кол-во" value={`${formData['Кол-во шин']} шт.`} />
                                     <DetailItem label="Наличие дисков" value={formData['Наличие дисков']} />
                                     <DetailItem label="DOT-код" value={formData['DOT-код']} />
                                </SectionBlock>

                                <div className="bg-yellow-50 dark:bg-yellow-900/10 border border-yellow-200 dark:border-yellow-800/30 rounded-xl p-4">
                                    <h4 className="text-xs font-bold text-yellow-600 dark:text-yellow-500 uppercase mb-2">Заметки</h4>
                                    <p className="text-sm text-gray-800 dark:text-gray-200 font-mono whitespace-pre-wrap">{descClean || 'Нет описания'}</p>
                                </div>

                                <SectionBlock title="Финансы" icon={<CashIcon/>}>
                                     <DetailItem label="Общая сумма" value={new Intl.NumberFormat('ru-RU', { style: 'currency', currency: 'RUB' }).format(Number(formData['Общая сумма'] || 0))} className="col-span-1 sm:col-span-1" />
                                     <DetailItem label="Цена за месяц" value={new Intl.NumberFormat('ru-RU', { style: 'currency', currency: 'RUB' }).format(Number(formData['Цена за месяц'] || 0))} />
                                     <DetailItem label="Срок хранения" value={`${formData['Срок']} мес.`} />
                                     <DetailItem label="Начало хранения" value={formatDateForDisplay(formData['Начало'])} />
                                </SectionBlock>

                                <SectionBlock title="Контакты" icon={<UserIcon/>}>
                                    <DetailItem label="Телефон" value={formData['Телефон']} />
                                    <DetailItem label="Chat ID" value={formData['Chat ID']} />
                                    <DetailItem label="Адрес клиента" value={formData['Адрес клиента']} className="col-span-1 sm:col-span-2" />
                                </SectionBlock>
                            </div>
                        )}

                        {activeTab === 'history' && <OrderHistory client={client} />}

                        {activeTab === 'photos' && <PhotoGallery client={client} refreshClientData={refreshData} showToast={showToast} />}
                    </div>
                )}
            </div>

            {/* Sticky Bottom Actions Bar (Mobile Optimized) */}
            <div className="sticky bottom-0 z-40 bg-white dark:bg-gray-900 border-t border-gray-200 dark:border-gray-800 p-3 sm:p-4 shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.1)] safe-area-inset-bottom">
                <div className="max-w-4xl mx-auto flex flex-wrap gap-2 justify-between items-center">

                    {mode === 'view' && (
                        <>
                            <div className="flex gap-2 w-full sm:w-auto">
                                <Button size="md" variant="secondary" onClick={() => setMode('edit')} className="flex-1 sm:flex-none justify-center">
                                    <EditIcon/> <span className="ml-1">Изм.</span>
                                </Button>
                                <Button size="md" variant="secondary" onClick={() => setMode('message')} className="flex-1 sm:flex-none justify-center">
                                    <MessageIcon/> <span className="ml-1">SMS</span>
                                </Button>
                                <Button size="md" variant="secondary" onClick={handleGenerateReceipt} className="flex-1 sm:flex-none justify-center !bg-indigo-50 !text-indigo-600 dark:!bg-indigo-900/30 dark:!text-indigo-300">
                                    <ReceiptIcon className="w-5 h-5"/>
                                </Button>
                            </div>

                            <div className="flex gap-2 w-full sm:w-auto mt-2 sm:mt-0">
                                <Button size="md" variant="primary" onClick={() => navigate('/add-client', { state: { clientToReorder: client } })} className="flex-1 sm:flex-none justify-center !bg-green-600 hover:!bg-green-700">
                                    <DocumentPlusIcon className="w-5 h-5 mr-1"/> Новый заказ
                                </Button>
                                <Button size="md" variant="danger" onClick={handleDelete} className="justify-center px-3">
                                    <DeleteIcon/>
                                </Button>
                            </div>
                        </>
                    )}

                    {mode === 'edit' && (
                        <div className="flex w-full gap-3">
                            <Button variant="outline" onClick={() => setMode('view')} disabled={isSubmitting} className="flex-1">Отмена</Button>
                            <Button onClick={handleSave} disabled={isSubmitting} className="flex-1">{isSubmitting ? 'Сохранение...' : 'Сохранить'}</Button>
                        </div>
                    )}

                    {mode === 'message' && (
                        <div className="flex w-full gap-3">
                            <Button variant="outline" onClick={() => setMode('view')} disabled={isSubmitting} className="flex-1">Назад</Button>
                            <Button onClick={handleSendMessage} disabled={isSubmitting || !client?.['Chat ID']} className="flex-1">{isSubmitting ? 'Отправка...' : 'Отправить'}</Button>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
};

import React from 'react';

interface CheckboxPillProps {
    name: string;
    checked: boolean;
    onChange: (e: React.ChangeEvent<HTMLInputElement>) => void;
    label: React.ReactNode;
}

export const CheckboxPill: React.FC<CheckboxPillProps> = ({ name, checked, onChange, label }) => (
    <label className="flex items-center space-x-3 p-3 bg-white dark:bg-gray-800/60 rounded-lg cursor-pointer border-2 border-gray-200 dark:border-gray-700 has-[:checked]:border-primary-500 has-[:checked]:bg-primary-50 dark:has-[:checked]:bg-primary-900/20 transition-all duration-200">
        <input type="checkbox" name={name} checked={checked} onChange={onChange} className="h-4 w-4 rounded border-gray-300 text-primary-600 focus:ring-primary-500" />
        <span className="text-sm font-medium text-gray-800 dark:text-gray-200">{label}</span>
    </label>
);

import React, { useState, useEffect, useRef } from 'react';

const STORAGE_MONTHS = Array.from({ length: 12 }, (_, i) => i + 1);

interface SmartDurationSelectorProps {
    value: number;
    onChange: (val: number) => void;
    minimal?: boolean;
}

export const SmartDurationSelector: React.FC<SmartDurationSelectorProps> = ({ value, onChange, minimal = false }) => {
    const [isActive, setIsActive] = useState(false);
    const wrapperRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (wrapperRef.current && !wrapperRef.current.contains(event.target as Node)) {
                setIsActive(false);
            }
        };
        document.addEventListener("mousedown", handleClickOutside);
        return () => document.removeEventListener("mousedown", handleClickOutside);
    }, []);

    return (
        <div className="relative flex flex-col items-center group w-full" ref={wrapperRef}>
            {!minimal && <span className="text-[10px] uppercase text-gray-400 font-medium tracking-wider mb-1 select-none">Срок</span>}
            <button
                type="button"
                onClick={() => setIsActive(!isActive)}
                className={`w-full text-center font-medium transition-all duration-200 ${minimal ? 'text-lg text-gray-900 dark:text-white' : 'text-2xl sm:text-3xl font-black tracking-tight leading-none border-b-2 pb-1'} ${
                    isActive 
                    ? minimal ? '' : 'text-primary-600 border-primary-500 scale-110' 
                    : minimal ? '' : 'text-gray-800 dark:text-gray-100 border-transparent hover:border-gray-300 dark:hover:border-gray-600'
                }`}
            >
                {value}<span className={`text-gray-500 ${minimal ? 'text-sm font-normal ml-1' : 'text-sm font-normal ml-1'}`}>мес</span>
            </button>

            {isActive && (
                <div className={`
                    fixed top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 z-[100] w-[90vw] max-w-[320px] 
                    sm:absolute sm:top-full sm:left-1/2 sm:-translate-x-1/2 sm:translate-y-0 sm:mt-2 sm:z-50 sm:w-[320px]
                    bg-white dark:bg-gray-800 rounded-xl shadow-2xl border border-gray-200 dark:border-gray-700 p-2 
                    animate-in fade-in zoom-in-95 duration-100
                `}>
                    <div className="grid grid-cols-4 gap-2 no-scrollbar">
                        {STORAGE_MONTHS.map((opt) => (
                            <button
                                key={opt}
                                type="button"
                                onClick={() => { onChange(opt); setIsActive(false); }}
                                className={`py-3 rounded-lg text-lg font-bold transition-colors ${
                                    value === opt
                                    ? 'bg-primary-600 text-white'
                                    : 'bg-gray-100 dark:bg-gray-700 text-gray-700 dark:text-gray-200 hover:bg-primary-100 dark:hover:bg-primary-900/30'
                                }`}
                            >
                                {opt}
                            </button>
                        ))}
                    </div>
                </div>
            )}
        </div>
    );
}

