interface ClientDetailsPageProps {
    clients: Client[];
    headers: string[];
    templates: MessageTemplate[];
    refreshData: () => Promise<void>;
}

export const ClientDetailsPage: React.FC<ClientDetailsPageProps> = ({ clients, headers, templates, refreshData }) => {
    const { id } = useParams();
    const navigate = useNavigate();

    // Find client immediately from props for instant display
    const [client, setClient] = useState<Client | undefined>(undefined);
    const [activeTab, setActiveTab] = useState<'details' | 'history' | 'photos'>('details');
    const [mode, setMode] = useState<'view' | 'edit' | 'message'>('view');
    const [formData, setFormData] = useState<Partial<Client> | null>(null);
    const [selectedTemplateName, setSelectedTemplateName] = useState<string>('');
    const [preview, setPreview] = useState('');
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [toast, setToast] = useState<{ message: string, type: 'success' | 'error' } | null>(null);

    // Edit Mode State
    const [tireGroups, setTireGroups] = useState<TireGroup[]>([]);
    const [draftGroup, setDraftGroup] = useState<TireGroup | null>(null);
    const [description, setDescription] = useState('');

    useEffect(() => {
        if (!id) return;
        // Use String() for ID comparison to handle potential number/string mismatches from URL/Data
        const foundClient = clients.find(c => String(c.id) === String(id));
        setClient(foundClient);
        setFormData(foundClient || null);
    }, [id, clients]);

    // Initialize edit mode state when switching to edit
    useEffect(() => {
        if (mode === 'edit' && formData) {
            const groups = parseGroupsFromClient(formData);
            setTireGroups(groups);

            // Extract description from 'Заказ - QR' (everything after ">>" on a new line or similar logic if needed)
            // But usually we just want to allow editing the current readable string OR structured data.
            // For now, let's keep it simple. If legacy string, description is just the string part that is not tires.
            const rawQR = formData['Заказ - QR'] || '';
            const descPart = rawQR.split('>>')[1];
            if (descPart) setDescription(descPart.trim());
        }
    }, [mode, formData]);

    // Recalculate fields during edit
    useEffect(() => {
        if (mode === 'edit' && formData) {
            setFormData(prev => prev ? calculateAllFields(prev, tireGroups, draftGroup) : null);
        }
    }, [tireGroups, draftGroup, mode]); // removed formData dependencies to avoid infinite loop, relying on user interaction to update specific fields

    const showToast = (message: string, type: 'success' | 'error') => {
        setToast({ message, type });
    };

    // Template Logic
    useEffect(() => {
        if (mode === 'message' && templates.length > 0 && !selectedTemplateName && preview === '') {
            setSelectedTemplateName(templates[0]?.['Название шаблона'] || '');
        }
    }, [templates, selectedTemplateName, mode, preview]);

    useEffect(() => {
        if (selectedTemplateName && formData) {
            const selectedTemplate = templates.find(t => t['Название шаблона'] === selectedTemplateName);
            if (selectedTemplate) {
                let content = selectedTemplate['Содержимое (HTML)'];
                Object.keys(formData).forEach(key => {
                    let value = formData[key as keyof Client];
                    if ((key === 'Начало' || key === 'Окончание' || key === 'Напомнить') && typeof value === 'string') {
                        if (value.includes('T')) value = value.split('T')[0];
                    }
                    if ((key === 'Общая сумма' || key === 'Долг' || key === 'Цена за месяц') && typeof value === 'number') {
                         value = new Intl.NumberFormat('ru-RU', { style: 'currency', currency: 'RUB', minimumFractionDigits: 0 }).format(value);
                    }
                    content = content.replace(new RegExp(`{{${key}}}`, 'g'), String(value || ''));
                });
                setPreview(content);
            }
        }
    }, [selectedTemplateName, templates, formData]);

    // Handler for regular inputs
    const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
        const { name, value, type } = e.target;
        const isCheckbox = type === 'checkbox';
        const { checked } = isCheckbox ? (e.target as HTMLInputElement) : { checked: false };
        setFormData(prev => prev ? ({ ...prev, [name]: isCheckbox ? checked : value }) : null);
    };

    const handleSave = async () => {
        if (!formData || !formData.id) return;
        setIsSubmitting(true);

        try {
            // Reconstruct derived strings from TireGroups for the legacy view
            const brands = Array.from(new Set(tireGroups.map(g => {
                const b = g.brand === 'Не указан' ? '' : g.brand;
                return `${b} ${g.model}`.trim();
            }))).filter(Boolean);

            const sizes = tireGroups.map(g => `${g.count}x ${g.width}/${g.profile}R${g.diameter}`);

            const readableDesc = tireGroups.map(g => {
                const brandStr = g.brand === 'Не указан' ? '' : g.brand;
                return `${g.count}x ${brandStr} ${g.model} ${g.width}/${g.profile}R${g.diameter}`.replace(/\s+/g, ' ').trim();
            }).join('\n');

            let fullReadable = readableDesc;
            if (description) fullReadable += `\n>> ${description}`;

            const jsonPayload = JSON.stringify({ groups: tireGroups, note: description });

            // Construct the update object
            const updatePayload: Partial<Client> = {
                ...formData,
                'Бренд_Модель': brands.join('\n'),
                'Размер шин': sizes.join('\n'),
                'Заказ - QR': fullReadable,
                'metadata': jsonPayload,
                // Ensure DOT is updated
                'DOT-код': tireGroups.map(g => g.dot).filter(Boolean).join(' / ')
            };

            await api.updateClient(updatePayload as Client);
            showToast('Клиент успешно обновлен', 'success');
            await refreshData();
            setMode('view');
        } catch (e: any) {
            showToast(e.message, 'error');
        } finally {
            setIsSubmitting(false);
        }
    };

    const handleDelete = async () => {
        if (!client) return;
        if (window.confirm(`Вы уверены, что хотите удалить клиента "${client['Имя клиента']}"?`)) {
            setIsSubmitting(true);
            try {
                await api.deleteClient(client.id);
                showToast('Клиент удален', 'success');
                await refreshData();
                navigate('/clients', { replace: true });
            } catch (e: any) {
                showToast(e.message, 'error');
            } finally {
                setIsSubmitting(false);
            }
        }
    };

    const handleSendMessage = async () => {
        if (preview && client) {
            setIsSubmitting(true);
            try {
                const result = await api.sendMessage(client['Chat ID'] as string, preview);
                showToast(result.message, result.success ? 'success' : 'error');
                if (result.success) {
                    await refreshData();
                    setMode('view');
                }
            } catch(e: any) {
                showToast(e.message, 'error');
            } finally {
                setIsSubmitting(false);
            }
        }
    };

    const handleGenerateReceipt = () => {
        if (!client) return;
        const groups = getTireGroups(client);
        const formatCurrency = (val: number | undefined) => new Intl.NumberFormat('ru-RU', { style: 'currency', currency: 'RUB', minimumFractionDigits: 0 }).format(val || 0);

        let tiresText = '';
        if (groups.length > 0) {
            tiresText = groups.map((g, i) => `<b>📦 Комплект ${i + 1}:</b>\n${g.count}шт • ${g.brand} ${g.model}\nРазмер: <b>${g.width}/${g.profile} R${g.diameter}</b>\nСезон: ${g.season} | Диски: ${g.hasRims}${g.dot ? `\nDOT: <b>${g.dot}</b>` : ''}`).join('\n\n');
        } else {
            tiresText = (client['Заказ - QR'] || '').split('||JSON:')[0];
        }

        const receiptHtml = `
<b>📃 ДЕТАЛИ ЗАКАЗА (ДОГОВОР)</b>

👤 <b>Клиент:</b> ${client['Имя клиента']}
🚗 <b>Авто:</b> ${client['Номер Авто']}
📞 <b>Телефон:</b> ${client['Телефон']}

🔢 <b>Договор №:</b> <code>${client['Договор']}</code>
📅 <b>Срок хранения:</b> ${client['Срок']} мес.
(с ${formatDateForDisplay(client['Начало'])} по ${formatDateForDisplay(client['Окончание'])})

- - - - - - - - - - - - - -
${tiresText}
- - - - - - - - - - - - - -

💰 <b>Сумма заказа:</b> ${formatCurrency(client['Общая сумма'])}
(Тариф: ${formatCurrency(client['Цена за месяц'])}/мес)
